48	// ── Canonical-fixture identities ─────────────────────────────
49	
50	/// Canonical RBRR prefix markers installed by case 1. Distinct from
51	/// pristine's throwaway prefixes (prlc-/prlr-) — case 2's probe detects
52	/// canonical state by reading the moniker's family stem from rbrr.env.
53	pub(crate) const RBTDRK_CANONICAL_CLOUD_PREFIX: &str = "canc-";
54	pub(crate) const RBTDRK_CANONICAL_RUNTIME_PREFIX: &str = "canr-";
55	
56	/// Family stem for canonical depots; six-digit auto-increment suffix per run.
57	/// Depots persist post-success for operator inspection; reruns pick the next
58	/// free suffix by walking depot_list output.
59	pub(crate) const RBTDRK_FAMILY_STEM: &str = "canest";
60	
61	/// Static identities for the canonical SA cycle. Stable across runs because
62	/// each run uses a fresh canest depot project.
63	const RBTDRK_IDENTITY_RETRIEVER: &str = "canest-ret";
64	const RBTDRK_IDENTITY_DIRECTOR: &str = "canest-dir";
65	
66	const RBTDRK_FAMILY_NUMERIC_FLOOR: u32 = 100000;
67	const RBTDRK_FAMILY_NUMERIC_WIDTH: usize = 6;
68	
69	const RBTDRK_FACT_EXT_DEPOT: &str = "depot";
70	const RBTDRK_FACT_EXT_DEPOT_PROJECT: &str = "depot-project";
71	const RBTDRK_FACT_GOVERNOR_SA_EMAIL: &str = "rbgp_fact_governor_sa_email";
72	
73	const RBTDRK_FIELD_RBRR_CLOUD_PREFIX: &str = "RBRR_CLOUD_PREFIX";
74	const RBTDRK_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
75	const RBTDRK_FIELD_RBRR_DEPOT_MONIKER: &str = "RBRR_DEPOT_MONIKER";
76	const RBTDRK_FIELD_RBRR_SECRETS_DIR: &str = "RBRR_SECRETS_DIR";
77	
78	const RBTDRK_RBRR_FILE: &str = ".rbk/rbrr.env";
79	const RBTDRK_RBRA_FILE: &str = "rbra.env";
