81	// ── Helpers ──────────────────────────────────────────────────
82	
83	/// Read an env-file value or None if absent. Mirrors pristine's helper —
84	/// kept local to avoid coupling canonical-establish to pristine-lifecycle.
85	fn rbtdrk_read_env_value(path: &Path, key: &str) -> Option<String> {
86	    let content = std::fs::read_to_string(path).ok()?;
87	    let prefix = format!("{}=", key);
88	    for line in content.lines() {
89	        let trimmed = line.trim_start();
90	        if trimmed.starts_with('#') {
91	            continue;
92	        }
93	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
94	            return Some(rest.to_string());
95	        }
96	    }
97	    None
98	}
99	
100	fn rbtdrk_resolve(root: &Path, raw: &str) -> PathBuf {
101	    if Path::new(raw).is_absolute() {
102	        PathBuf::from(raw)
103	    } else {
104	        root.join(raw)
105	    }
106	}
107	
108	fn rbtdrk_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
109	    let mut result: String = content
110	        .lines()
111	        .map(|line| {
112	            for (key, value) in pairs {
113	                let assign = format!("{}=", key);
114	                if line.starts_with(&assign) {
115	                    return format!("{}{}", assign, value);
116	                }
117	            }
118	            line.to_string()
119	        })
120	        .collect::<Vec<_>>()
121	        .join("\n");
122	    if content.ends_with('\n') {
123	        result.push('\n');
124	    }
125	    result
126	}
127	
128	fn rbtdrk_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
129	    let add = Command::new("git")
130	        .args(["add", file])
131	        .current_dir(root)
132	        .output()
133	        .map_err(|e| format!("rbtdrk: git add invocation failed: {}", e))?;
134	    if !add.status.success() {
135	        return Err(format!(
136	            "rbtdrk: git add failed (exit {}): {}",
137	            add.status.code().unwrap_or(-1),
138	            String::from_utf8_lossy(&add.stderr).trim()
139	        ));
140	    }
141	    let commit = Command::new("git")
142	        .args(["commit", "-m", message])
143	        .current_dir(root)
144	        .output()
145	        .map_err(|e| format!("rbtdrk: git commit invocation failed: {}", e))?;
146	    if !commit.status.success() {
147	        return Err(format!(
148	            "rbtdrk: git commit failed (exit {}): {}",
149	            commit.status.code().unwrap_or(-1),
150	            String::from_utf8_lossy(&commit.stderr).trim()
151	        ));
152	    }
153	    Ok(())
154	}
