206	fn rbtdrk_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
207	    let rbrr = root.join(RBTDRK_RBRR_FILE);
208	    let content = std::fs::read_to_string(&rbrr)
209	        .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
210	    let new_content =
211	        rbtdrk_replace_env_fields(&content, &[(RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker)]);
212	    std::fs::write(&rbrr, &new_content)
213	        .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
214	    let commit_msg = format!(
215	        "canonical-establish fixture: set {}={}",
216	        RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker
217	    );
218	    rbtdrk_git_add_and_commit(root, RBTDRK_RBRR_FILE, &commit_msg)
219	}
